UPDATE vip_benefit_transfer
SET status = 20, transaction_number = #{transactionNumber}
WHERE service_fee_order_no = #{feeOrderNo} AND status = 10

mapper.select:
SELECT t.transfer_id AS transferId, t.vip_benefit_id AS vipBenefitId, t.from_user_id AS fromUserId, t.to_user_id AS toUserId, t.from_store_id AS fromStoreId, t.to_store_id AS toStoreId, t.service_fee AS serviceFee, t.service_fee_order_no AS serviceFeeOrderNo, t.transaction_number AS transactionNumber, t.status, t.audit_user_id AS auditUserId, t.audit_time AS auditTime, t.audit_remark AS auditRemark, t.confirm_deadline AS confirmDeadline, t.refund_status AS refundStatus, t.created_date AS createdDate, t.effect_time AS effectTime, c.card_name AS cardName FROM vip_benefit_transfer t LEFT JOIN vip_benefit b ON t.vip_benefit_id = b.vip_benefit_id LEFT JOIN vip_benefit_card c ON b.vip_card_id = c.vip_card_id
AND t.from_user_id = #{userId} AND t.to_user_id = #{userId} AND (t.from_user_id = #{userId} OR t.to_user_id = #{userId})
AND t.status = #{status}
ORDER BY t.created_date DESC
LIMIT #{offset}, #{limit}

SELECT COUNT(1)
FROM vip_benefit_transfer t


        AND t.from_user_id = #{userId}
        AND t.to_user_id = #{userId}
        AND (t.from_user_id = #{userId} OR t.to_user_id = #{userId})


        AND t.status = #{status}
